// Handler creates http.Handler with routing matching OpenAPI spec.
func Handler(si ServerInterface) http.Handler {
	return HandlerWithOptions(si, GorillaServerOptions{})
}

type GorillaServerOptions struct {
	BaseURL          string
	BaseRouter       *mux.Router
	Middlewares      []MiddlewareFunc
	ErrorHandlerFunc func(w http.ResponseWriter, r *http.Request, err error)
}

// HandlerFromMux creates http.Handler with routing matching OpenAPI spec based on the provided mux.
func HandlerFromMux(si ServerInterface, r *mux.Router) http.Handler {
	return HandlerWithOptions(si, GorillaServerOptions{
		BaseRouter: r,
	})
}

func HandlerFromMuxWithBaseURL(si ServerInterface, r *mux.Router, baseURL string) http.Handler {
	return HandlerWithOptions(si, GorillaServerOptions{
		BaseURL:    baseURL,
		BaseRouter: r,
	})
}

// HandlerWithOptions creates http.Handler with additional options
func HandlerWithOptions(si ServerInterface, options GorillaServerOptions) http.Handler {
	r := options.BaseRouter

	if r == nil {
		r = mux.NewRouter()
	}
	if options.ErrorHandlerFunc == nil {
		options.ErrorHandlerFunc = func(w http.ResponseWriter, r *http.Request, err error) {
			http.Error(w, err.Error(), http.StatusBadRequest)
		}
	}
	wrapper := ServerInterfaceWrapper{
		Handler:            si,
		HandlerMiddlewares: options.Middlewares,
		ErrorHandlerFunc:   options.ErrorHandlerFunc,
	}

	r.HandleFunc(options.BaseURL+"/accounts", wrapper.CreateAccount).Methods(http.MethodPost)

	r.HandleFunc(options.BaseURL+"/accounts/{id}", wrapper.GetAccount).Methods(http.MethodGet)

	r.HandleFunc(options.BaseURL+"/accounts/{id}/deposit", wrapper.Deposit).Methods(http.MethodPost)

	r.HandleFunc(options.BaseURL+"/accounts/{id}/status", wrapper.SetAccountStatus).Methods(http.MethodPost)

	r.HandleFunc(options.BaseURL+"/accounts/{id}/withdraw", wrapper.Withdraw).Methods(http.MethodPost)

	r.HandleFunc(options.BaseURL+"/admin/disputes", wrapper.ListDisputes).Methods(http.MethodGet)

	r.HandleFunc(options.BaseURL+"/admin/disputes/{id}/resolve", wrapper.ResolveDispute).Methods(http.MethodPost)

	r.HandleFunc(options.BaseURL+"/admin/expire-holds", wrapper.ExpireHolds).Methods(http.MethodPost)

	r.HandleFunc(options.BaseURL+"/admin/reconcile", wrapper.Reconcile).Methods(http.MethodGet)

	r.HandleFunc(options.BaseURL+"/health", wrapper.Health).Methods(http.MethodGet)

	r.HandleFunc(options.BaseURL+"/transfers/pending", wrapper.ListPendingTransfers).Methods(http.MethodGet)

	r.HandleFunc(options.BaseURL+"/transfers/{id}", wrapper.GetTransfer).Methods(http.MethodGet)

	r.HandleFunc(options.BaseURL+"/transfers/{id}/reverse", wrapper.ReverseTransfer).Methods(http.MethodPost)

	r.HandleFunc(options.BaseURL+"/users", wrapper.CreateUser).Methods(http.MethodPost)

	r.HandleFunc(options.BaseURL+"/users/{id}", wrapper.GetUser).Methods(http.MethodGet)

	r.HandleFunc(options.BaseURL+"/users/{id}/accounts", wrapper.ListUserAccounts).Methods(http.MethodGet)

	return r
}
